import { api } from '@semparar/mf-app-user';
import { AxiosResponse } from 'axios';
import { call, put } from 'redux-saga/effects';

import {
  GetMarketplaceResponse,
  getMarketplaceActions,
} from '../../ducks/getMarketplace';

export function* getMarketplace(payload: { data: Record<string, string> }) {
  try {
    const urlParams = new URLSearchParams(payload.data);
    const response: AxiosResponse<GetMarketplaceResponse> = yield call(
      api.get,
      `/marketplace/v1/vertem/getToken?${urlParams.toString()}`,
    );
    if (response.data.status.codigoRetorno === 0) {
      yield put(getMarketplaceActions.successGetMarketplace(response.data));
    } else {
      yield put(getMarketplaceActions.failedGetMarketplace());
    }
  } catch {
    yield put(getMarketplaceActions.failedGetMarketplace());
  }
}

